/**
 * This is an example of how you can chain modals together and return any entered data to a nanoflow.
 * 
 * Config it to whatever spec is needed.
 * @returns {Promise.<string>}
 */
export async function JS_Modal_Chaining() {
	// BEGIN USER CODE
	return new Promise(async (resolve, reject) => {
		let continueRunning = true;

		const steps = ['1', '2', '3'];
		const swalQueueStep = Swal.mixin({
			showConfirmButton: true,
			confirmButtonText: 'Next',
			showCancelButton: true,
			cancelButtonText: 'Cancel',
			showDenyButton: true,
			denyButtonText: 'Back',
			progressSteps: steps,
			input: 'text',
			inputAttributes: {
			required: true
			},
			allowOutsideClick: false,
			validationMessage: 'This field is required',
			showClass: { backdrop: 'swal2-noanimation' },
			hideClass: { backdrop: 'swal2-noanimation' },
		});

		async function backAndForward() {
			var values = [];
			let currentStep;

            for (currentStep = 0; currentStep < steps.length && continueRunning; ) {
				const result = await new swalQueueStep({
					title: 'Question ' + steps[currentStep],
					showDenyButton: currentStep > 0,
					currentProgressStep: currentStep
				});

				if (result.dismiss === 'cancel') {
                    continueRunning = false;
					values = undefined;
				}

				if (result.value) {
					values[currentStep] = result.value;
					currentStep++;
				} else if (result.isDenied) {
					currentStep--;
				}
			}

			resolve(JSON.stringify(values));
		}

		backAndForward();
	});
	// END USER CODE
}
